"use client";
import { useState, useEffect } from "react";
import Link from "next/link";
import { createClient } from "@/lib/supabase";
import type { User } from "@supabase/supabase-js";
import { NAV_LINKS } from "@/lib/nav-constants";

/**
 * 모바일 메뉴 버튼과 드롭다운 (클라이언트 컴포넌트)
 * - NAV_LINKS는 nav-constants.ts에서 공유
 * - 인증 상태에 따라 로그인/회원가입 또는 마이페이지/로그아웃 표시
 */
export default function MobileMenu() {
    const [isMenuOpen, setIsMenuOpen] = useState(false);
    const [user, setUser] = useState<User | null>(null);

    // Escape 키로 메뉴 닫기
    useEffect(() => {
        if (!isMenuOpen) return;
        const handleKeyDown = (e: KeyboardEvent) => {
            if (e.key === "Escape") setIsMenuOpen(false);
        };
        document.addEventListener("keydown", handleKeyDown);
        return () => document.removeEventListener("keydown", handleKeyDown);
    }, [isMenuOpen]);

    useEffect(() => {
        const supabase = createClient();

        supabase.auth.getUser().then(({ data }: { data: { user: User | null } }) => {
            setUser(data.user);
        });

        const { data: { subscription } } = supabase.auth.onAuthStateChange(
            (_event: string, session: { user: User } | null) => {
                setUser(session?.user ?? null);
            }
        );

        return () => subscription.unsubscribe();
    }, []);

    const handleLogout = async () => {
        const supabase = createClient();
        await supabase.auth.signOut();
        setIsMenuOpen(false);
        window.location.href = "/";
    };

    return (
        <>
            {/* 햄버거 버튼 */}
            <button
                onClick={() => setIsMenuOpen(!isMenuOpen)}
                className="md:hidden p-2 text-gray-600 hover:text-indigo-600 rounded-lg hover:bg-indigo-50 transition-colors"
                aria-label={isMenuOpen ? "메뉴 닫기" : "메뉴 열기"}
                aria-expanded={isMenuOpen}
            >
                <svg
                    className="w-6 h-6"
                    fill="none"
                    stroke="currentColor"
                    viewBox="0 0 24 24"
                    aria-hidden="true"
                >
                    {isMenuOpen ? (
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                    ) : (
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
                    )}
                </svg>
            </button>

            {/* 오버레이 */}
            {isMenuOpen && (
                <div
                    className="md:hidden fixed inset-0 bg-black/30 z-40"
                    onClick={() => setIsMenuOpen(false)}
                    aria-hidden="true"
                />
            )}

            {/* 모바일 드롭다운 */}
            {isMenuOpen && (
                <div className="md:hidden glass border-t border-indigo-100 shadow-lg absolute top-full left-0 right-0 z-50">
                    <nav className="max-w-7xl mx-auto px-6 py-4" aria-label="모바일 내비게이션">
                        {NAV_LINKS.map((link) => (
                            <Link
                                key={link.href}
                                href={link.href}
                                className="block py-3 text-gray-600 hover:text-indigo-600 transition-colors font-medium"
                                onClick={() => setIsMenuOpen(false)}
                            >
                                {link.label}
                            </Link>
                        ))}
                        <div className="border-t border-gray-200 mt-4 pt-4 space-y-3">
                            {user ? (
                                <>
                                    <Link
                                        href="/dashboard"
                                        className="block py-2 text-gray-600 hover:text-indigo-600"
                                        onClick={() => setIsMenuOpen(false)}
                                    >
                                        마이페이지
                                    </Link>
                                    <button
                                        onClick={handleLogout}
                                        className="w-full text-left py-2 text-gray-600 hover:text-indigo-600"
                                    >
                                        로그아웃
                                    </button>
                                </>
                            ) : (
                                <>
                                    <Link
                                        href="/login"
                                        className="block py-2 text-gray-600 hover:text-indigo-600"
                                        onClick={() => setIsMenuOpen(false)}
                                    >
                                        로그인
                                    </Link>
                                    <Link
                                        href="/signup"
                                        className="btn-primary w-full justify-center"
                                        onClick={() => setIsMenuOpen(false)}
                                    >
                                        회원가입
                                    </Link>
                                </>
                            )}
                        </div>
                    </nav>
                </div>
            )}
        </>
    );
}
