import { createBrowserClient } from '@supabase/ssr'

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL
const supabaseAnonKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY

export function createClient() {
    if (!supabaseUrl || !supabaseAnonKey) {
        // 환경 변수가 없으면 더미 클라이언트 반환 (개발용)
        return {
            auth: {
                getUser: async () => ({ data: { user: null }, error: null }),
                signInWithPassword: async () => ({ error: { message: 'Supabase가 설정되지 않았습니다. .env.local 파일을 확인해주세요.' } }),
                signUp: async () => ({ error: { message: 'Supabase가 설정되지 않았습니다. .env.local 파일을 확인해주세요.' } }),
                signInWithOAuth: async () => ({ error: { message: 'Supabase가 설정되지 않았습니다. .env.local 파일을 확인해주세요.' } }),
                signOut: async () => ({ error: null }),
                onAuthStateChange: () => ({ data: { subscription: { unsubscribe: () => { } } } }),
                exchangeCodeForSession: async () => ({ error: { message: 'Supabase가 설정되지 않았습니다.' } }),
            },
        } as ReturnType<typeof createBrowserClient>
    }

    return createBrowserClient(supabaseUrl, supabaseAnonKey)
}

export function isSupabaseConfigured() {
    return !!(supabaseUrl && supabaseAnonKey)
}
