"use client";
import Link from "next/link";
import Image from "next/image";
import { useState, useEffect, useRef } from "react";
import { createClient } from "@/lib/supabase";
import type { User } from "@supabase/supabase-js";
import { ChevronDownIcon } from "@/components/icons";

/**
 * 인증 상태에 따라 로그인/회원가입 버튼 또는 사용자 드롭다운을 렌더링하는 클라이언트 컴포넌트
 * Header 서버 컴포넌트에서 분리하여 전체 Header의 SSR 유지
 */
export default function AuthMenu() {
    const [user, setUser] = useState<User | null>(null);
    const [dropdownOpen, setDropdownOpen] = useState(false);
    const dropdownRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const supabase = createClient();

        const refreshUser = () => {
            supabase.auth.getUser().then(({ data }: { data: { user: User | null } }) => {
                setUser(data.user);
            });
        };

        refreshUser();

        const { data: { subscription } } = supabase.auth.onAuthStateChange(
            (_event: string, session: { user: User } | null) => {
                setUser(session?.user ?? null);
            }
        );

        window.addEventListener("profile-updated", refreshUser);

        const handleClickOutside = (e: MouseEvent) => {
            if (dropdownRef.current && !dropdownRef.current.contains(e.target as Node)) {
                setDropdownOpen(false);
            }
        };
        document.addEventListener("mousedown", handleClickOutside);

        const handleKeyDown = (e: KeyboardEvent) => {
            if (e.key === "Escape") setDropdownOpen(false);
        };
        document.addEventListener("keydown", handleKeyDown);

        return () => {
            subscription.unsubscribe();
            window.removeEventListener("profile-updated", refreshUser);
            document.removeEventListener("mousedown", handleClickOutside);
            document.removeEventListener("keydown", handleKeyDown);
        };
    }, []);

    const handleLogout = async () => {
        const supabase = createClient();
        await supabase.auth.signOut();
        window.location.href = "/";
    };

    if (!user) {
        return (
            <>
                <Link
                    href="/login"
                    className="text-xs sm:text-sm font-bold text-slate-600 px-2 sm:px-3 py-1 hover:text-slate-800 transition-colors"
                >
                    로그인
                </Link>
                <Link
                    href="/signup"
                    className="text-xs sm:text-sm font-bold bg-indigo-600 text-white px-3 sm:px-4 py-1.5 sm:py-2 rounded-lg hover:bg-indigo-700 transition-colors whitespace-nowrap"
                >
                    회원가입
                </Link>
            </>
        );
    }

    const isAdmin = user.app_metadata?.role === "admin" || user.user_metadata?.role === "admin";

    return (
        <div className="relative" ref={dropdownRef}>
            <button
                onClick={() => setDropdownOpen(!dropdownOpen)}
                className="flex items-center gap-2 px-3 py-2 rounded-lg hover:bg-indigo-50 transition-colors"
                aria-expanded={dropdownOpen}
                aria-haspopup="true"
                aria-label="사용자 메뉴"
            >
                <div className="w-8 h-8 bg-gradient-to-br from-indigo-500 to-indigo-500 rounded-full flex items-center justify-center text-white font-medium text-sm overflow-hidden relative">
                    {user.user_metadata?.profile_image_url ? (
                        <Image
                            src={user.user_metadata.profile_image_url}
                            alt="프로필"
                            fill
                            className="object-cover"
                        />
                    ) : (
                        user.user_metadata?.name?.[0] || user.email?.[0]?.toUpperCase() || "U"
                    )}
                </div>
                <ChevronDownIcon />
            </button>

            {dropdownOpen && (
                <div className="absolute right-0 mt-2 w-48 bg-white rounded-xl shadow-lg border border-gray-100 py-2 animate-fade-in-up" style={{ animationDuration: "0.15s" }}>
                    <div className="px-4 py-2 border-b border-gray-100">
                        <p className="text-sm font-medium text-gray-800 truncate">
                            {user.user_metadata?.name || "사용자"}
                        </p>
                        <p className="text-xs text-gray-500 truncate">{user.email}</p>
                    </div>
                    <Link
                        href="/dashboard"
                        className="block px-4 py-2 text-sm text-gray-600 hover:bg-indigo-50 hover:text-indigo-600 transition-colors"
                        onClick={() => setDropdownOpen(false)}
                    >
                        마이페이지
                    </Link>
                    {isAdmin && (
                        <Link
                            href="/admin"
                            className="block px-4 py-2 text-sm text-gray-600 hover:bg-indigo-50 hover:text-indigo-600 transition-colors"
                            onClick={() => setDropdownOpen(false)}
                        >
                            관리자 패널
                        </Link>
                    )}
                    <button
                        onClick={handleLogout}
                        className="w-full text-left px-4 py-2 text-sm text-gray-600 hover:bg-indigo-50 hover:text-indigo-600 transition-colors"
                    >
                        로그아웃
                    </button>
                </div>
            )}
        </div>
    );
}
